     1→/*
     2→ * sinf() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly sinf  (test_sinf_opt.elf)
     6→ *   2. Linked with toolchain's default sinf        (test_sinf_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→#ifdef EN_PERF
    16→#define PF_COUNTER
    17→#include "nds_pfcounter.h"
    18→#endif
    19→
    20→static inline uint32_t f2u(float f)
    21→{
    22→    union { float f; uint32_t u; } x;
    23→    x.f = f;
    24→    return x.u;
    25→}
    26→
    27→static inline float u2f(uint32_t u)
    28→{
    29→    union { float f; uint32_t u; } x;
    30→    x.u = u;
    31→    return x.f;
    32→}
    33→
    34→#ifndef EN_PERF
    35→static void emit(float x)
    36→{
    37→    float r = sinf(x);
    38→    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
    39→}
    40→
    41→static void emit_u(uint32_t bits)
    42→{
    43→    emit(u2f(bits));
    44→}
    45→
    46→/* ------------------------------------------------------------------ */
    47→/* Test points                                                         */
    48→/* ------------------------------------------------------------------ */
    49→
    50→/* 1. Special values */
    51→static void test_special(void)
    52→{
    53→    /* Zeros */
    54→    emit(0.0f);
    55→    emit(-0.0f);
    56→
    57→    /* NaN */
    58→    emit_u(0x7fc00000u); /* qNaN */
    59→    emit_u(0x7f800001u); /* sNaN */
    60→    emit_u(0xffc00000u); /* -NaN */
    61→
    62→    /* Infinity */
    63→    emit_u(0x7f800000u); /* +Inf */
    64→    emit_u(0xff800000u); /* -Inf */
    65→}
    66→
    67→/* 2. Tiny values: sin(x) ~ x */
    68→static void test_tiny(void)
    69→{
    70→    emit_u(0x00000001u); /* min denorm */
    71→    emit_u(0x80000001u);
    72→    emit_u(0x00400000u); /* mid denorm */
    73→    emit_u(0x80400000u);
    74→    emit_u(0x007fffffu); /* max denorm */
    75→    emit_u(0x807fffffu);
    76→    emit(FLT_MIN);
    77→    emit(-FLT_MIN);
    78→    emit(1.0e-20f);
    79→    emit(-1.0e-20f);
    80→    emit(1.0e-10f);
    81→    emit(-1.0e-10f);
    82→}
    83→
    84→/* 3. Known mathematical values */
    85→static void test_known(void)
    86→{
    87→    float pi   = 3.14159265358979323846f;
    88→    float pi_2 = 1.57079632679489661923f;
    89→    float pi_3 = 1.04719755119659774615f;
    90→    float pi_4 = 0.78539816339744830962f;
    91→    float pi_6 = 0.52359877559829887308f;
    92→
    93→    emit(pi_6);
    94→    emit(pi_4);
    95→    emit(pi_3);
    96→    emit(pi_2);
    97→    emit(pi);
    98→    emit(2.0f * pi);
    99→    emit(-pi_6);
   100→    emit(-pi_4);
   101→    emit(-pi_2);
   102→    emit(-pi);
   103→    emit(3.0f * pi_2);
   104→    emit(pi_2 + 0.001f);
   105→    emit(pi + 0.001f);
   106→    emit(pi - 0.001f);
   107→}
   108→
   109→/* 4. Large arguments */
   110→static void test_large(void)
   111→{
   112→    float vals[] = {
   113→        10.0f, 100.0f, 1000.0f, 100000.0f, 1000000.0f,
   114→        -10.0f, -1000.0f,
   115→        3.14159265f * 100.0f,
   116→        3.14159265f * 1000.0f,
   117→        1.0e10f, 1.0e20f,
   118→        -1.0e10f, -1.0e20f,
   119→        FLT_MAX, -FLT_MAX,
   120→    };
   121→    int n = sizeof(vals) / sizeof(vals[0]);
   122→    for (int i = 0; i < n; i++)
   123→        emit(vals[i]);
   124→}
   125→
   126→/* 5. Quadrant transitions */
   127→static void test_quadrant(void)
   128→{
   129→    float pi_2 = 1.5707963267948966f;
   130→    float offsets[] = { -1e-5f, 0.0f, 1e-5f };
   131→    int noff = sizeof(offsets) / sizeof(offsets[0]);
   132→
   133→    for (int k = 1; k <= 8; k++) {
   134→        float boundary = (float)((double)k * (double)pi_2);
   135→        for (int j = 0; j < noff; j++)
   136→            emit(boundary + offsets[j]);
   137→    }
   138→}
   139→
   140→/* 6. Worst-case argument reduction */
   141→static void test_hard(void)
   142→{
   143→    float cases[] = {
   144→        u2f(0x40490fdbu), /* pi as float */
   145→        u2f(0x40c90fdbu), /* 2*pi as float */
   146→        u2f(0x4096cbe4u), /* 3*pi/2 */
   147→        4.0f, 16.0f, 64.0f, 256.0f,
   148→    };
   149→    int n = sizeof(cases) / sizeof(cases[0]);
   150→    for (int i = 0; i < n; i++) {
   151→        emit(cases[i]);
   152→        emit(-cases[i]);
   153→    }
   154→}
   155→
   156→/* 7. Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
   157→static void test_sweep(void)
   158→{
   159→    float hi = 4.0f * 3.14159265358979323846f;
   160→    int nsteps = 200;
   161→    float step = hi / (float)nsteps;
   162→
   163→    /* [0, 4*pi] */
   164→    for (int i = 0; i <= nsteps; i++)
   165→        emit((float)i * step);
   166→
   167→    /* [-4*pi, 0] */
   168→    for (int i = 0; i <= nsteps; i++)
   169→        emit(-hi + (float)i * step);
   170→}
   171→
   172→/* 8. Sample [0, pi/4] every 4194304 ULP (~250 cases) */
   173→static void test_exhaustive_small(void)
   174→{
   175→    uint32_t end = 0x3f490fdbu; /* pi/4 */
   176→    for (uint32_t b = 0; b <= end; b += 4194304)
   177→        emit_u(b);
   178→}
   179→
   180→/* 9. Random sweep: 300 evenly spaced inputs */
   181→static void test_random_300(void)
   182→{
   183→    float lo = -6.2831853f;
   184→    float hi =  6.2831853f;
   185→    int n = 300;
   186→    for (int i = 0; i < n; i++) {
   187→        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
   188→        emit(x);
   189→    }
   190→}
   191→#endif
   192→
   193→/* ------------------------------------------------------------------ */
   194→
   195→#ifdef EN_PERF
   196→static void perf(float x)
   197→{
   198→    volatile float acc = 0.0f;
   199→    volatile float xx = x;
   200→    startPFM;
   201→    for (int i = 0; i < 100; i++)
   202→        acc += sinf(xx+i);
   203→    stopPFM;
   204→    readResult();
   205→    printf("perf %08lx: %08lx\n",
   206→           (unsigned long)f2u(x),
   207→           (unsigned long)f2u((float)acc));
   208→}
   209→#endif /* EN_PERF */
   210→
   211→/* ------------------------------------------------------------------ */
   212→
   213→int main(void)
   214→{
   215→#ifdef EN_PERF
   216→    perf(1.0f);
   217→#else
   218→    test_special();
   219→    test_tiny();
   220→    test_known();
   221→    test_large();
   222→    test_quadrant();
   223→    test_hard();
   224→    test_sweep();
   225→    test_exhaustive_small();
   226→    test_random_300();
   227→#endif
   228→    return 0;
   229→}
